import polars as pl
from polars import DataFrame


def label_encode_ordinal(
    df: DataFrame, col_name: str, ordered_categories: list[str], unknown_value: int = -1
) -> DataFrame:
    """Encodes ordinal string column to integers. Null values must be imputed first. No rows dropped."""
    mapping = {cat: idx for idx, cat in enumerate(ordered_categories)}
    expr = pl.lit(unknown_value).cast(pl.Int32)
    for cat, idx in reversed(mapping.items()):
        expr = pl.when(pl.col(col_name) == cat).then(pl.lit(idx).cast(pl.Int32)).otherwise(expr)
    return df.with_columns(expr.alias(col_name))


df = label_encode_ordinal(
    df, col_name="education_level",
    ordered_categories=["high school", "associate", "bachelors", "masters", "phd"],
)
# high school=0, associate=1, bachelors=2, masters=3, phd=4
```

Pure Polars `when/then` chaining — no Pandas, no sklearn. After mode imputation every row gets a valid integer. Rows are preserved.

