import polars as pl
from polars import DataFrame
import json


def save_cleaning_params(params: dict, path: str = "cleaning_params.json") -> None:
    with open(path, "w") as f:
        json.dump(params, f, indent=2, default=str)
    print(f"Cleaning params saved: {path}")


def load_cleaning_params(path: str = "cleaning_params.json") -> dict:
    with open(path) as f:
        return json.load(f)


def apply_saved_params(df: DataFrame, params: dict) -> DataFrame:
    """Applies pre-computed medians/modes to a DataFrame. No rows dropped."""
    fill_exprs = []
    for col_name, val in params.get("numeric_medians", {}).items():
        if col_name in df.columns:
            fill_exprs.append(pl.col(col_name).fill_null(val))
    for col_name, val in params.get("string_modes", {}).items():
        if col_name in df.columns:
            fill_exprs.append(pl.col(col_name).fill_null(val))
    if fill_exprs:
        df = df.with_columns(fill_exprs)
    return df


# Training: compute and save
params = {
    "numeric_medians": {"age": df.select(pl.col("age").median()).item()},
    "string_modes":    {"city": "New York"},
    "version": "1",
}
save_cleaning_params(params, "cleaning_params_v1.json")

# Production: load and apply — no rows dropped
prod_params = load_cleaning_params("cleaning_params_v1.json")
prod_df = apply_saved_params(prod_df, prod_params)
```

All values applied via `fill_null` — no rows dropped. The params file is versioned so you always know which training-set statistics were used.

