import polars as pl
from polars import DataFrame
from datetime import datetime


def normalize_datetime_column(
    df: DataFrame, col_name: str, target_timezone: str = "UTC"
) -> DataFrame:
    """Converts datetime to uniform timezone. Null datetimes imputed with median. No rows dropped."""
    dtype = df.schema[col_name]
    if isinstance(dtype, pl.Datetime) and dtype.time_zone is not None:
        df = df.with_columns(
            pl.col(col_name).dt.convert_time_zone(target_timezone).alias(col_name)
        )
    elif isinstance(dtype, pl.Datetime) and dtype.time_zone is None:
        df = df.with_columns(
            pl.col(col_name).dt.replace_time_zone(target_timezone).alias(col_name)
        )

    has_nulls = df.select(pl.col(col_name).is_null().any()).item()
    if has_nulls:
        median_epoch_us = int(
            df.select(pl.col(col_name).cast(pl.Int64).median()).item()
        )
        median_dt = datetime.utcfromtimestamp(median_epoch_us / 1_000_000)
        df = df.with_columns(
            pl.col(col_name).fill_null(
                pl.lit(median_dt).cast(pl.Datetime(time_unit="us", time_zone=target_timezone))
            ).alias(col_name)
        )
        print(f"'{col_name}': null datetimes imputed with median {median_dt}")
    return df
```

Casts to `Int64` microseconds for median computation, converts back to timezone-aware `Datetime`. Null datetimes imputed with median — no rows dropped. All Polars.

