import polars as pl
from polars import DataFrame
import json
from typing import Optional


def run_production_pipeline(
    df: DataFrame,
    params_path: str = "cleaning_params_v1.json",
    phone_col: Optional[str] = None,
    email_col: Optional[str] = None,
    verbose: bool = True,
) -> DataFrame:
    """
    Applies all cleaning steps using pre-computed training parameters.
    No rows are dropped. No medians are recomputed — uses saved training values.
    """
    params = load_cleaning_params(params_path)
    original_rows = len(df)
    if verbose:
        print(f"Production pipeline v{params.get('version', '?')}: {original_rows} rows")

    if "schema" in params:
        schema_map = {col: getattr(pl, dtype) for col, dtype in params["schema"].items()}
        df = validate_schema(df, schema_map, strict=False)

    df = apply_saved_params(df, params)
    if verbose:
        print("Step 2: saved median/mode imputation applied")

    if "iqr_fences" in params:
        df = apply_saved_iqr_fences(df, params["iqr_fences"])
        if verbose:
            print("Step 3: saved IQR fences applied")

    if "valid_ranges" in params:
        for col_name, rng in params["valid_ranges"].items():
            median_val = params["numeric_medians"].get(col_name)
            if median_val is not None and col_name in df.columns:
                df = df.with_columns(
                    pl.when(
                        (pl.col(col_name) < rng["min"]) | (pl.col(col_name) > rng["max"])
                    ).then(median_val).otherwise(pl.col(col_name)).alias(col_name)
                )

    if phone_col:
        df = clean_phone_numbers(df, col_name=phone_col)
    if email_col:
        df = clean_email(df, col_name=email_col, impute_mode=False)

    assert len(df) == original_rows, "Production pipeline bug: row count changed!"
    if verbose:
        print(f"Pipeline complete: {len(df)} rows (unchanged). Zero rows dropped.")
    return df


prod_df_clean = run_production_pipeline(
    prod_df, params_path="cleaning_params_v1.json",
    phone_col="phone_number", email_col="email",
)
```

Single entry point for production. Loads params, validates schema, applies all saved values, asserts row count. All Polars, fully idempotent.
